/* ── Falling Hearts Canvas ── */
const HeartsCanvas = () => {
  const ref = useRef(null);

  useEffect(() => {
    // jsdom (used by CRA tests) doesn't implement canvas.getContext reliably.
    if (typeof window === "undefined" || typeof document === "undefined") return;

    const canvas = ref.current;
    if (!canvas) return;

    let raf;
    let ctx;
    try {
      ctx = canvas.getContext("2d");
    } catch {
      ctx = null;
    }

    // If canvas context isn't available, skip animation.
    if (!ctx) return;

    const resize = () => {

      canvas.width = canvas.offsetWidth;
      canvas.height = canvas.offsetHeight;
    };

    resize();
    window.addEventListener("resize", resize);

    const HEARTS = "♥ ❤ 💕 💗 💖 ✿".split(" ");
    const count = 38;
    const particles = Array.from({ length: count }, (_, i) => ({
      x: Math.random() * window.innerWidth,
      y: -40 - Math.random() * 600,
      size: Math.random() * 18 + 8,
      speed: Math.random() * 0.8 + 0.3,
      drift: (Math.random() - 0.5) * 0.4,
      opacity: Math.random() * 0.45 + 0.12,
      symbol: HEARTS[Math.floor(Math.random() * HEARTS.length)],
      wobble: Math.random() * Math.PI * 2,
      wobbleSpeed: Math.random() * 0.02 + 0.008,
      idx: i,
    }));

    const colors = ["#FF6B9D", "#C84B7A", "#FFB6C1", "#E8A0BF", "#b45ff5", "#d4a0f7"];

    const draw = () => {
      if (!ctx) return;
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach((p) => {

        p.y += p.speed;
        p.wobble += p.wobbleSpeed;
        p.x += Math.sin(p.wobble) * 0.6 + p.drift;

        if (p.y > canvas.height + 40) {
          p.y = -40;
          p.x = Math.random() * canvas.width;
        }

        ctx.save();
        ctx.globalAlpha = p.opacity;
        ctx.font = `${p.size}px serif`;
        ctx.fillStyle = colors[p.idx % colors.length];
        ctx.fillText(p.symbol, p.x, p.y);
        ctx.restore();
      });

      raf = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
    };
  }, []);

  return <canvas ref={ref} className="mj-canvas" style={{ width: "100%", height: "100%" }} />;
};



